K=$(grep -E '^N8N_API_KEY=' /root/Iryna_Karmazina/.env | tail -1 | cut -d= -f2-)
python3 - "$K" << 'PYEOF'
import json,sys,urllib.request,urllib.error,time
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'; WID='1YdXnLFOXI85IsWv'
def once(method,u,data=None):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    return urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=8)
def get_budget(u,budget):
    t=time.monotonic()
    while time.monotonic()-t<budget:
        try: return json.load(once('GET',u))
        except Exception: time.sleep(3)
    return None
start=time.monotonic()
d=get_budget('workflows/'+WID,60)
if d is None: print('GET не вдався за 60с (n8n блимає) — повторити'); sys.exit()
open('/root/wf-backup-dash-sticky.json','w').write(json.dumps(d))
old_th='<th style="padding:8px">'
new_th='<th style="padding:8px;position:sticky;top:0;background:#fff;z-index:3;border-bottom:1px solid #d8d6cd;white-space:nowrap">'
old_sort="String(delDate(a)||'9999').localeCompare(String(delDate(b)||'9999'))"
new_sort="String(relDate(a)||'9999-99-99').localeCompare(String(relDate(b)||'9999-99-99'))"
old_scr='<td colspan="17" style="padding:7px 10px;background:#EEF1FB;'
new_scr='<td colspan="17" style="scroll-margin-top:48px;padding:7px 10px;background:#EEF1FB;'
patched=False
for n in d['nodes']:
    if n.get('type')=='n8n-nodes-base.code':
        c=(n.get('parameters') or {}).get('jsCode','')
        if 'work-start' in c:
            n1=c.count(old_th); c=c.replace(old_th,new_th)
            c=c.replace(old_sort,new_sort)
            n3=c.count(old_scr); c=c.replace(old_scr,new_scr)
            print('th=%d scroll=%d'%(n1,n3))
            if n1>=1 and n3>=1: n['parameters']['jsCode']=c; patched=True
print('patched:',patched)
if patched:
    payload={'name':d['name'],'nodes':d['nodes'],'connections':d['connections'],'settings':d.get('settings',{})}
    if d.get('staticData') is not None: payload['staticData']=d['staticData']
    body=json.dumps(payload).encode('utf-8')
    ok=False
    while time.monotonic()-start<105:
        try: r=once('PUT','workflows/'+WID,body); print('PUT',r.status); ok=True; break
        except Exception as e: time.sleep(3)
    if ok:
        try: once('POST','workflows/'+WID+'/activate'); print('activate ok')
        except Exception: print('activate later')
        d2=get_budget('workflows/'+WID,15)
        if d2: print('verify sticky:',any('position:sticky' in (x.get('parameters') or {}).get('jsCode','') for x in d2['nodes'] if x.get('type')=='n8n-nodes-base.code'),'| active:',d2.get('active'))
    else: print('PUT не вдався (n8n блимає)')
PYEOF
